  ('elementary-64311456-moex-00370', 'elementary-64311456', 'elementary-64311456-moex-113-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '在下列何種情境中，案主對於社會工作者產生情感轉移的狀況？', '["案主覺得社會工作者就像自己親近的大姊姊一樣，做什麼決定都希望得到社會工作者的認同", "案主很明確的將自己的困難和期待告訴社會工作者", "案主不習慣與不熟悉的社會工作者互動", "案主不習慣和不同性別的社會工作者一起工作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:08+00:00", "source_pdf_sha1": "5c9616efa256", "answer_pdf_sha1": "58ee787f2e9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
